import request from '@/utils/request'

//获取首页轮播图
export function getcCarousel() {
    return request({
      url: '/geekplus/getCarousel',
      method: 'get',
    })
}

// 查询首页网站友情链接，is_display=1,表示显示
export function displayFriendlyLink() {
  return request({
    url: '/geekplus/displayFriendlyLink',
    method: 'get',
    //params: query
  })
}

// 网站用户评论留言
export function sendUserComment(data) {
  return request({
    url: '/geekplus/userCommentMessage',
    method: 'post',
    data: data
  })
}

// 获取用户的留言信息
export function getAllUserComment(params) {
  return request({
    url: '/geekplus/getAllUserComment',
    method: 'get',
    params: params
  })
}

// 获取用户的留言评论数量
export function getUserCommentCount() {
  return request({
    url: '/geekplus/getUserCommentCount',
    method: 'get'
  })
}

// 获取最新的十条用户的留言评论
export function getLatestUserComment() {
  return request({
    url: '/geekplus/getLatestUserComment',
    method: 'get'
  })
}

//获取疫情数据
export function getcovid() {
    return request({
      url: '/covid/getAllData',
      method: 'get',
    })
}

//获取世界疫情数据
export function getWorldCovid() {
    return request({
      url: '/covid/getCovid19Foreign',
      method: 'get',
    })
}

//获取世界疫情数据
export function get163coviddata() {
  return request({
    url: '/163coviddata',
    method: 'get',
  })
}
